import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import Chart from 'chart.js/auto';
import { MedicineService } from '../../services/medicine.service';

@Component({
  selector: 'app-pharmacy',
  templateUrl: './pharmacy.component.html',
  styleUrls: ['./pharmacy.component.scss']
})
export class PharmacyComponent implements OnInit {

  stats = [
    { title: 'Total Customer', count: 25 },
    { title: 'Total Medicine', count: 0 },
    { title: 'Total Manufactures', count: 25 }
  ];

  medicines: any[] = [];

  constructor(private router: Router, private medicineService: MedicineService) {}

  ngOnInit(): void {
    this.medicineService.getAll().subscribe({
      next: (data) => {
        this.medicines = data;
        this.stats[1].count = data.length;
      },
      error: () => {}
    });
    this.initCharts();
  }

  initCharts() {
    new Chart("lineChart", {
      type: 'line',
      data: {
        labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
        datasets: [{ label: 'Purchases', data: [1200, 1900, 1500, 2500, 2200, 3000, 2800], borderColor: '#6c92f4', tension: 0.4 }]
      }
    });
    new Chart("pieChart", {
      type: 'doughnut',
      data: {
        labels: ['Chrome', 'Safari', 'Firefox'],
        datasets: [{ data: [300, 50, 100], backgroundColor: ['#ffcd56', '#4bc0c0', '#ff6384'] }]
      }
    });
    new Chart("barChart", {
      type: 'bar',
      data: {
        labels: ['Jan', 'Feb', 'Mar'],
        datasets: [{ label: 'Stock', data: [10, 20, 30], backgroundColor: '#4e73df' }]
      }
    });
  }
}
